"use strict";parserFactory.register("readingpia.me",()=>new ReadingpiaParser);class ReadingpiaParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".content a:has(div)")].map(e=>this.linkToChapter(e)).reverse()}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("div span").textContent}}findContent(e){return e.querySelector("div#chapter-body")||e.querySelector("div.chapter-body")||e.querySelector("main > div:not(.advertisement):not(.promo-container):not(.comments):not([style])")}extractTitleImpl(e){return e.querySelector("h2.novel-title")}extractAuthor(e){let r=e.querySelector(".info-ans");return r?.textContent??super.extractAuthor(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novel-cover")}getInformationEpubItemChildNodes(e){return[e.querySelector(".novel-synopsis")]}}